SELECT COUNT(*)
FROM SPW_CMS_PAGE
WHERE AB_GROUP_ID = #{groupId}
  AND PAGE_ID     = #{pageId}
  AND USE_YN      = 'Y'
  AND PAGE_TYPE   = 'PAGE'

mapper.update:
UPDATE SPW_CMS_PAGE
SET AB_WEIGHT        = 0,
    LAST_MODIFIER_ID = #{modifierId}
WHERE AB_GROUP_ID = #{groupId}
  AND PAGE_ID  != #{winnerPageId}
  AND USE_YN    = 'Y'
  AND PAGE_TYPE = 'PAGE'

UPDATE SPW_CMS_PAGE
SET AB_WEIGHT        = 1,
    LAST_MODIFIER_ID = #{modifierId}
WHERE PAGE_ID   = #{winnerPageId}
  AND USE_YN    = 'Y'
  AND PAGE_TYPE = 'PAGE'
